	private final SimpleValueFactory vf = SimpleValueFactory.getInstance();

	@Test
	void flushToBranchDetachesPrependedStatementModelsBeforeClosingTransferredChangeset() throws SailException {
		SailSourceBranch parent = new SailSourceBranch(createBackingSource(), CloseAwareModel::new);
		SailSourceBranch child = new SailSourceBranch(parent, CloseAwareModel::new);

		SailSink parentWriter = parent.sink(IsolationLevels.NONE);
		SailSink observer = child.sink(IsolationLevels.NONE);
		SailSink writer = child.sink(IsolationLevels.NONE);
		Statement parentApproved = vf.createStatement(vf.createIRI("urn:parent:s"), vf.createIRI("urn:parent:p"),
				vf.createLiteral("parent:o"));
		Statement approved = vf.createStatement(vf.createIRI("urn:approved:s"), vf.createIRI("urn:approved:p"),
				vf.createLiteral("approved:o"));

		try {
			parentWriter.approve(parentApproved);
			parentWriter.flush();
			parentWriter.close();

			observer.observe(vf.createIRI("urn:observed:s"), vf.createIRI("urn:observed:p"), vf.createLiteral("x"));
			writer.approve(approved);
			writer.flush();
			writer.close();

			child.flush();

			assertDoesNotThrow(observer::prepare);
		} finally {
			parentWriter.close();
			writer.close();
			observer.close();
			child.close();
			parent.close();
		}
	}

